const redis = require('./redisClient');
const db = require('../db');
const BETA = Number(process.env.CACHE_BETA || 1.0);
const TTL = Number(process.env.CACHE_TTL || 90);

async function getFeatured(catId) {
  const key = `featured:${catId}`;
  const raw = await redis.get(key);
  if (raw) {
    const { v, delta, exp } = JSON.parse(raw);
    const now = Date.now() / 1000;
    // XFetch: recompute early with rising probability near expiry
    if (now - delta * BETA * Math.log(Math.random()) >= exp) {
      recompute(key, catId).catch(() => {});
    }
    return v;
  }
  return recompute(key, catId);
}

async function recompute(key, catId) {
  const lockKey = `lock:${key}`;
  const got = await redis.set(lockKey, '1', 'NX', 'PX', 5000);
  if (!got) {
    const raw = await redis.get(key);
    if (raw) return JSON.parse(raw).v;
    return db.aggregateFeatured(catId); // rare cold path
  }
  try {
    const t0 = Date.now();
    const rows = await db.aggregateFeatured(catId);
    const delta = (Date.now() - t0) / 1000;
    const exp = Date.now() / 1000 + TTL;
    await redis.set(key, JSON.stringify({ v: rows, delta, exp }), 'EX', TTL + 10);
    return rows;
  } finally {
    await redis.del(lockKey);
  }
}
module.exports = { getFeatured };

