@Injectable()
export class QuoteService {
  private cache = new Map<string, {v:Quote, exp:number}>();
  constructor(private rates: RateEngine) {}
  async getQuote(pair: string): Promise<Quote> {
    const c = this.cache.get(pair);
    if (c && c.exp > Date.now()) return c.v;
    const q = await this.rates.fetch(pair); // 120ms upstream
    this.cache.set(pair, { v: q, exp: Date.now() + 200 });
    return q;
  }
}

@Injectable()
export class QuoteService {
  private cache = new Map<string, {v:Quote, exp:number}>();
  private inFlight = new Map<string, Promise<Quote>>();
  constructor(private rates: RateEngine) {}

  async getQuote(pair: string): Promise<Quote> {
    const c = this.cache.get(pair);
    if (c && c.exp > Date.now()) return c.v;
    const existing = this.inFlight.get(pair);
    if (existing) return existing;
    const p = this.load(pair);
    this.inFlight.set(pair, p);
    try { return await p; } finally { this.inFlight.delete(pair); }
  }

  private async load(pair: string): Promise<Quote> {
    const q = await this.rates.fetch(pair);
    this.cache.set(pair, { v: q, exp: Date.now() + 200 });
    return q;
  }
}

