package flags

func (s *Service) Eval(ctx context.Context, flag, user string) bool {
  if v, ok := s.l1.Get(flag); ok {
    return s.match(v.(string), user)
  }
  val, err := s.redis.Get(ctx, "flag:"+flag).Result()
  if err != nil { return false }
  s.l1.Add(flag, val)
  return s.match(val, user)
}

package flags

func (s *Service) StartInvalidator(ctx context.Context) {
  sub := s.redis.Subscribe(ctx, "flag-changed")
  ch := sub.Channel()
  go func() {
    for msg := range ch {
      s.l1.Remove(msg.Payload) // evict; next read reloads from L2
    }
  }()
}

func (s *Service) SetFlag(ctx context.Context, flag, rule string) error {
  if err := s.redis.Set(ctx, "flag:"+flag, rule, 0).Err(); err != nil { return err }
  return s.redis.Publish(ctx, "flag-changed", flag).Err()
}

