export async function resolveHandle(handle: string): Promise<string|null> {
  const key = `h:${handle}`;
  const hit = await redis.get(key);
  if (hit) return hit;
  const row = await db.userByHandle(handle); // index scan
  if (row) { await redis.set(key, row.id, 'EX', 600); return row.id; }
  return null; // miss never cached -> next probe hits DB again
}

const NEG = '\u0000neg';

export async function resolveHandle(handle: string): Promise<string|null> {
  const key = `h:${handle}`;
  const hit = await redis.get(key);
  if (hit === NEG) return null;          // negative cache hit
  if (hit) return hit;                    // positive cache hit
  const row = await db.userByHandle(handle);
  if (row) {
    await redis.set(key, row.id, 'EX', 600);
    return row.id;
  }
  await redis.set(key, NEG, 'EX', 30);    // short negative TTL
  return null;
}

export async function registerHandle(handle: string, userId: string) {
  await db.insertHandle(handle, userId);
  await redis.del(`h:${handle}`); // clear any negative sentinel immediately
}

