const TTL = 30;
function jitter() { return TTL + Math.floor(Math.random() * 15); }

export async function getLeaderboard(): Promise<Row[]> {
  const hit = await redis.get('lb:global');
  if (hit) return JSON.parse(hit);
  return recompute();
}

export async function recompute(): Promise<Row[]> {
  const got = await redis.set('lb:lock', '1', 'NX', 'PX', 5000);
  if (!got) {
    const stale = await redis.get('lb:stale');
    if (stale) return JSON.parse(stale);
    return []; // brief building state, only on truly cold start
  }
  try {
    const rows = await db.rankedAggregate();
    const json = JSON.stringify(rows);
    await redis.set('lb:global', json, 'EX', jitter());
    await redis.set('lb:stale', json, 'EX', 3600); // long-lived fallback
    return rows;
  } finally {
    await redis.del('lb:lock');
  }
}

