const crypto = require('crypto');
const ALLOW = ['origin','dest','depart','ret','pax','cabin','sort'];

function canonicalize(params) {
  const norm = {};
  for (const k of ALLOW) {
    if (params[k] == null || params[k] === '') continue;
    let v = params[k];
    if (Array.isArray(v)) v = [...v].sort().join(',');
    norm[k] = String(v).trim().toLowerCase();
  }
  const serialized = Object.keys(norm).sort().map(k => `${k}=${norm[k]}`).join('&');
  return crypto.createHash('sha1').update(serialized).digest('hex');
}
module.exports = { canonicalize, ALLOW };

