import DataLoader from 'dataloader';

export function makeUserLoader() {
  return new DataLoader<string, User>(async (ids) => {
    const keys = ids.map(id => `user:${id}`);
    const cached = await redis.mget(keys);
    const result: (User|null)[] = new Array(ids.length).fill(null);
    const missIdx: number[] = [];
    cached.forEach((c, i) => { if (c) result[i] = JSON.parse(c); else missIdx.push(i); });
    if (missIdx.length) {
      const missIds = missIdx.map(i => ids[i]);
      const rows = await db.usersByIds(missIds); // one IN query
      const byId = new Map(rows.map(r => [r.id, r]));
      const pipe = redis.pipeline();
      missIdx.forEach(i => {
        const u = byId.get(ids[i]) || null;
        result[i] = u;
        if (u) pipe.set(`user:${ids[i]}`, JSON.stringify(u), 'EX', 300);
      });
      await pipe.exec();
    }
    return result;
  });
}

