export default {
  async fetch(req, env) {
    // cache key is just the URL -> tenants collide
    const cache = caches.default;
    let res = await cache.match(req);
    if (res) return res;
    res = await fetch(req); // origin
    res = new Response(res.body, res);
    res.headers.set('Cache-Control', 'public, max-age=60');
    await cache.put(req, res.clone());
    return res;
  }
};

import { verifyJwt } from './jwt';

export default {
  async fetch(req, env) {
    const claims = await verifyJwt(req.headers.get('Authorization'), env.JWT_PUBKEY);
    if (!claims) return new Response('unauthorized', { status: 401 });
    const tenant = claims.tid;
    const cacheKey = new Request(new URL(req.url).toString() + '#t=' + tenant, req);
    const cache = caches.default;
    let res = await cache.match(cacheKey);
    if (res) return res;
    res = await fetch(req);
    res = new Response(res.body, res);
    res.headers.set('Cache-Control', 'public, max-age=60');
    res.headers.set('Surrogate-Key', 'tenant-' + tenant);
    await cache.put(cacheKey, res.clone());
    return res;
  }
};

export async function verifyJwt(header, pubkeyPem) {
  if (!header || !header.startsWith('Bearer ')) return null;
  const token = header.slice(7);
  try {
    const { payload } = await jwtVerify(token, await importSpki(pubkeyPem), { algorithms: ['RS256'] });
    return payload; // contains tid
  } catch { return null; }
}

