export async function listSummaries(ids: string[]) {
  const vers = await Promise.all(ids.map(ver));
  const keys = ids.map((id, i) => `art:sum:${id}:${vers[i]}`);
  const cached = await redis.mget(keys);
  const out: any[] = [];
  const missIds: string[] = [];
  cached.forEach((c, i) => c ? out.push(JSON.parse(c)) : missIds.push(ids[i]));
  if (missIds.length) {
    const docs = await mongo.articles.find({ _id: { $in: missIds } }, { projection: SUMMARY_PROJ }).toArray();
    for (const d of docs) {
      const v = await ver(d._id);
      await redis.set(`art:sum:${d._id}:${v}`, JSON.stringify(toSummary(d)), 'EX', 300);
      out.push(toSummary(d));
    }
  }
  return out;
}

