export const buffer = new Map<string, any>();

export function startFlusher() {
  setInterval(async () => {
    if (buffer.size === 0) return;
    const entries = [...buffer.entries()];
    buffer.clear();
    const pipe = redis.pipeline();
    for (const [dev, r] of entries) pipe.set(`dev:${dev}`, JSON.stringify(r));
    try {
      await pipe.exec();
    } catch (e) {
      // re-stage failed entries so a Redis blip does not lose data
      for (const [dev, r] of entries) if (!buffer.has(dev)) buffer.set(dev, r);
    }
  }, 1000);
}

