const BUCKETS = 16;
const local = new Map<string, number>();
const bucket = Math.floor(Math.random() * BUCKETS); // per-instance bucket

export function recordView(postId: string) {
  local.set(postId, (local.get(postId) || 0) + 1); // in-memory, no network
}

export function startFlusher() {
  setInterval(async () => {
    if (local.size === 0) return;
    const entries = [...local.entries()];
    local.clear();
    const pipe = redis.pipeline();
    for (const [postId, n] of entries) pipe.incrby(`views:${postId}:{b${bucket}}`, n);
    try { await pipe.exec(); }
    catch { for (const [p, n] of entries) local.set(p, (local.get(p) || 0) + n); } // re-stage
  }, 500);
}

export async function getViews(postId: string) {
  const keys = Array.from({ length: BUCKETS }, (_, i) => `views:${postId}:{b${i}}`);
  const vals = await redis.mget(keys);
  return vals.reduce((s, v) => s + Number(v || 0), 0);
}

