class Breaker {
  constructor({ failureThreshold = 5, openMs = 5000, timeoutMs = 150 } = {}) {
    this.fails = 0; this.state = 'closed'; this.openedAt = 0;
    this.failureThreshold = failureThreshold; this.openMs = openMs; this.timeoutMs = timeoutMs;
  }
  isOpen() {
    if (this.state === 'open' && Date.now() - this.openedAt > this.openMs) { this.state = 'half'; return false; }
    return this.state === 'open';
  }
  async exec(fn) {
    try {
      const r = await Promise.race([fn(), new Promise((_, rej) => setTimeout(() => rej(new Error('timeout')), this.timeoutMs))]);
      if (this.state === 'half') { this.state = 'closed'; this.fails = 0; }
      return r;
    } catch (e) {
      if (++this.fails >= this.failureThreshold || this.state === 'half') { this.state = 'open'; this.openedAt = Date.now(); }
      throw e;
    }
  }
}
const breaker = new Breaker();
module.exports = { breaker, Breaker };

