export async function getGraph(repoId: string) {
  const hit = await redis.get(`graph:${repoId}`);
  if (hit) return JSON.parse(hit);
  const locked = await redis.setnx(`graph:lock:${repoId}`, '1'); // no TTL!
  if (!locked) {
    while (true) { // spins forever if holder crashed
      await delay(100);
      const v = await redis.get(`graph:${repoId}`);
      if (v) return JSON.parse(v);
    }
  }
  const g = await compute(repoId); // may crash mid-way
  await redis.set(`graph:${repoId}`, JSON.stringify(g), 'EX', 600);
  await redis.del(`graph:lock:${repoId}`);
  return g;
}

import { randomUUID } from 'crypto';

const RELEASE = `if redis.call('get', KEYS[1]) == ARGV[1] then return redis.call('del', KEYS[1]) else return 0 end`;

export async function acquire(key: string, ttlMs = 10000) {
  const token = randomUUID();
  const ok = await redis.set(key, token, 'NX', 'PX', ttlMs);
  return ok ? token : null;
}
export function extend(key: string, ttlMs = 10000) {
  return redis.pexpire(key, ttlMs);
}
export function release(key: string, token: string) {
  return redis.eval(RELEASE, 1, key, token); // only delete if we own it
}

import { acquire, extend, release } from './lock';

export async function getGraph(repoId: string) {
  const hit = await redis.get(`graph:${repoId}`);
  if (hit) return JSON.parse(hit);
  const lockKey = `graph:lock:${repoId}`;
  const token = await acquire(lockKey);
  if (!token) return waitOrFallback(repoId);
  const watchdog = setInterval(() => extend(lockKey).catch(()=>{}), 4000);
  try {
    const g = await compute(repoId);
    await redis.set(`graph:${repoId}`, JSON.stringify(g), 'EX', 600);
    return g;
  } finally {
    clearInterval(watchdog);
    await release(lockKey, token); // safe: only deletes our token
  }
}

async function waitOrFallback(repoId: string) {
  const deadline = Date.now() + 8000;
  while (Date.now() < deadline) {
    await delay(150);
    const v = await redis.get(`graph:${repoId}`);
    if (v) return JSON.parse(v);
  }
  return compute(repoId); // degrade: recompute rather than hang forever
}

