import { encode, decode } from '@msgpack/msgpack';
import { createHash } from 'crypto';

const BUCKETS = 4096;
function bucket(sid: string) {
  const h = createHash('md5').update(sid).digest();
  return `sess:h:${h.readUInt16BE(0) % BUCKETS}`;
}

export async function getSession(sid: string) {
  const raw = await redis.hgetBuffer(bucket(sid), sid);
  if (!raw) return null;
  const d: any = decode(raw);
  if (d._exp && d._exp < Date.now()) { await redis.hdel(bucket(sid), sid); return null; }
  return d;
}

export async function setSession(sid: string, data: SessionData) {
  const payload = encode({ ...data, _exp: Date.now() + 86400_000 });
  await redis.hset(bucket(sid), sid, Buffer.from(payload));
}

export async function sweepExpired() {
  // sample buckets and drop expired fields to reclaim memory
  for (let i = 0; i < 4096; i++) {
    const key = `sess:h:${i}`;
    const all = await redis.hgetallBuffer(key);
    const now = Date.now();
    const dead = Object.entries(all).filter(([, v]) => (decode(v as Buffer) as any)._exp < now).map(([f]) => f);
    if (dead.length) await redis.hdel(key, ...dead);
  }
}

