func (c *Cache) Get(ctx context.Context, key string) ([]byte, error) {
  if v, ok := c.store.Get(key); ok {
    return v.([]byte), nil
  }
  // expired or missing -> rebuild, errors propagate to caller
  data, err := c.upstream.Fetch(ctx, key)
  if err != nil {
    return nil, err // user sees an error even if stale was usable
  }
  c.store.SetWithTTL(key, data, c.ttl)
  return data, nil
}

type entry struct{ data []byte; freshUntil, staleUntil time.Time }

func (c *Cache) Get(ctx context.Context, key string) ([]byte, error) {
  if e, ok := c.load(key); ok {
    now := time.Now()
    if now.Before(e.freshUntil) {
      return e.data, nil // fresh
    }
    if now.Before(e.staleUntil) {
      go c.singleFlightRebuild(key) // refresh in background
      c.metrics.ServedStale.Inc()
      return e.data, nil           // serve stale immediately
    }
  }
  return c.blockingRebuild(ctx, key) // beyond grace -> must rebuild or error
}

func (c *Cache) singleFlightRebuild(key string) {
  c.sf.Do(key, func() {
    data, err := c.upstream.Fetch(context.Background(), key)
    if err != nil {
      c.extendStale(key) // keep last-good usable through the grace window
      return
    }
    c.set(key, data)
  })
}

func (c *Cache) blockingRebuild(ctx context.Context, key string) ([]byte, error) {
  v, err, _ := c.sf.Do(key, func() (interface{}, error) {
    data, err := c.upstream.Fetch(ctx, key)
    if err != nil { return nil, err }
    c.set(key, data)
    return data, nil
  })
  if err != nil { return nil, err }
  return v.([]byte), nil
}

func (c *Cache) set(key string, data []byte) {
  now := time.Now()
  c.store.Set(key, entry{data: data, freshUntil: now.Add(c.fresh), staleUntil: now.Add(c.fresh + c.grace)})
}

func (c *Cache) extendStale(key string) {
  if e, ok := c.load(key); ok {
    e.staleUntil = time.Now().Add(c.grace) // keep serving last-good within grace
    c.store.Set(key, e)
  }
}

func TestServesStaleWhenUpstreamFails(t *testing.T) {
  c := newTestCache(100*time.Millisecond, 5*time.Minute)
  c.upstream = okThenFail()
  c.Get(ctx, "k")                    // warms with fresh
  time.Sleep(150 * time.Millisecond) // now stale-within-grace
  v, err := c.Get(ctx, "k")          // upstream now failing
  if err != nil { t.Fatal("expected stale served, got error") }
  if string(v) == "" { t.Fatal("expected stale data") }
}

