    r.set(f'ship:{sid}', json.dumps(doc), ex=300)
    return doc

def on_write(sid):
    r.delete(f'ship:{sid}')  # invalidate -> next read cold-misses

def run_cdc_warmer():
    for ev in cdc_stream('shipments'):
        sid = ev['after']['id']
        doc = es.get_shipment(sid)        # fetch the fresh denormalized doc
        r.set(f'ship:{sid}', json.dumps(doc), ex=300)  # refresh, not delete
        metrics.warmed.inc()

def get_shipment(sid):
    hit = r.get(f'ship:{sid}')
    if hit:
        metrics.hits.inc()
        return json.loads(hit)
    metrics.misses.inc()
    doc = es.get_shipment(sid)
    r.set(f'ship:{sid}', json.dumps(doc), ex=300)
    return doc

from time import monotonic
_last = {}

def should_refresh(sid, min_interval=1.0):
    now = monotonic()
    if now - _last.get(sid, 0) < min_interval:
        return False  # coalesce bursts of events for the same shipment
    _last[sid] = now
    return True

