async function addPoints(user, delta) {
  const cur = Number(await redis.get(`pts:${user}`) || 0);
  const next = cur + delta;          // read-modify-write race
  await redis.set(`pts:${user}`, String(next));
  await db.recordLedger(user, delta);
  return next;
}

async function addPoints(user, delta, idempotencyKey) {
  // record of truth + outbox atomically; idempotencyKey dedupes retries
  const applied = await db.tx(async (t) => {
    const dup = await t.exists('rewards_idem', idempotencyKey);
    if (dup) return false;
    await t.recordLedger(user, delta, idempotencyKey);
    await t.insertOutbox('points_added', { user, delta, idempotencyKey });
    return true;
  });
  return applied; // cache updated asynchronously by the worker
}

async function getPoints(user) {
  return Number(await redis.get(`pts:${user}`) || 0);
}

async function processOutbox() {
  for (const ev of await db.fetchOutbox('points_added')) {
    // SADD returns 0 if already applied -> idempotent cache update
    const fresh = await redis.sadd('pts:applied', ev.payload.idempotencyKey);
    if (fresh === 1) {
      await redis.incrby(`pts:${ev.payload.user}`, ev.payload.delta); // atomic, no lost updates
    }
    await db.markOutboxDone(ev.id);
  }
}

it('concurrent increments are not lost', async () => {
  await Promise.all(Array.from({length: 50}, (_, i) => addPoints('u1', 2, `k${i}`)));
  await processOutbox();
  expect(await getPoints('u1')).toBe(100);
});
it('retry with same idempotency key does not double-credit', async () => {
  await addPoints('u1', 5, 'same');
  await addPoints('u1', 5, 'same'); // retry
  await processOutbox();
  expect(await getPoints('u1')).toBe(5);
});

export async function checkPermission(userId: string, action: string): Promise<boolean> {
  const res = await authz.evaluate(userId, action); // 35ms, every request
  return res.allowed;
}

const cache = new LRUCache<string, boolean>({ max: 200000, ttl: 60000 });

export async function checkPermission(userId: string, action: string): Promise<boolean> {
  try {
    if (await isRevoked(userId)) return false;            // revocation wins
    const k = `${userId}:${action}`;
    const cached = cache.get(k);
    if (cached !== undefined) return cached;
    const res = await authz.evaluate(userId, action);
    cache.set(k, res.allowed);
    return res.allowed;
  } catch (e) {
    return false;  // fail closed
  }
}

export async function isRevoked(userId: string): Promise<boolean> {
  return (await redis.sismember('revoked', userId)) === 1;
}

export async function revoke(userId: string) {
  await redis.sadd('revoked', userId);
  await redis.expire('revoked', 3600); // revocations naturally age out after re-eval window
  await redis.publish('authz-revoke', userId); // evict local caches everywhere
}

export function startRevocationSubscriber() {
  redis.subscribe('authz-revoke');
  redis.on('message', (_ch, userId) => cache.delForUser(userId));
}

it('cuts authz calls on repeated checks', async () => {
  let calls = 0;
  authz.evaluate = async () => { calls++; return { allowed: true }; };
  for (let i = 0; i < 1000; i++) await checkPermission('u1', 'read');
  expect(calls).toBe(1);
});
it('revocation denies within the window even if cached allow exists', async () => {
  authz.evaluate = async () => ({ allowed: true });
  await checkPermission('u1', 'read'); // cached allow
  await revoke('u1');
  expect(await checkPermission('u1', 'read')).toBe(false);
});

func (c *Cache) Get(id string) (*Campaign, error) {
  raw, err := c.rdb.Get(ctx, "camp:"+id).Bytes()
  if err != nil { return nil, err }
  var camp Campaign
  if err := json.Unmarshal(raw, &camp); err != nil { return nil, err } // hot, allocates
  return &camp, nil
}

