  return c.rdb.Set(ctx, "camp:"+id, b, 5*time.Minute).Err()
}

syntax = "proto3";
package adserve;
option go_package = "./pb";

message Campaign {
  string id = 1;
  int64 budget_cents = 2;
  repeated string targeting = 3;
  double bid_floor = 4;
  int64 updated_at = 5;
}

import "google.golang.org/protobuf/proto"

func (c *Cache) Get(id string) (*pb.Campaign, error) {
  raw, err := c.rdb.Get(ctx, "camp:"+id).Bytes()
  if err != nil { return nil, err }
  camp := &pb.Campaign{}
  if err := proto.Unmarshal(raw, camp); err != nil {
    return nil, ErrCacheMiss // malformed -> treat as miss, let caller refetch
  }
  return camp, nil
}

func (c *Cache) Set(id string, camp *pb.Campaign) error {
  b, err := proto.Marshal(camp) // no reflection, compact
  if err != nil { return err }
  return c.rdb.Set(ctx, "camp:"+id, b, 5*time.Minute).Err()
}

func TestRoundTrip(t *testing.T) {
  c := newTestCache()
  in := &pb.Campaign{Id: "x", BudgetCents: 1000, Targeting: []string{"us"}}
  c.Set("x", in)
  out, err := c.Get("x")
  if err != nil || out.BudgetCents != 1000 { t.Fatalf("round trip failed: %v", err) }
}
func TestMalformedTreatedAsMiss(t *testing.T) {
  c := newTestCache()
  c.rdb.Set(ctx, "camp:y", []byte{0xff, 0x00, 0x13}, time.Minute)
  _, err := c.Get("y")
  if err != ErrCacheMiss { t.Fatalf("expected miss on malformed, got %v", err) }
}

