const MIN = 120, MAX = 21600; // 2 min .. 6 hours

export function adaptiveTtl(activityScore: number): number {
  // high activity -> short TTL (fresher); low activity -> long TTL (cheaper)
  const base = Math.round(MAX / (1 + activityScore));
  const bounded = Math.min(MAX, Math.max(MIN, base));
  const jitter = Math.floor(Math.random() * Math.min(60, bounded * 0.1));
  return bounded + jitter;
}

