export default {
  async fetch(req) {
    const cache = caches.default;
    let res = await cache.match(req);
    if (res) return res;
    res = await fetch(req);
    res = new Response(res.body, res);
    res.headers.set('Cache-Control', 'public, max-age=60'); // caches 5xx too!
    await cache.put(req, res.clone());
    return res;
  }
};

export default {
  async fetch(req) {
    const cache = caches.default;
    const cached = await cache.match(req);
    const fresh = await fetch(req);

    if (fresh.status >= 500) {
      // do NOT cache errors; serve last good stale if we have it
      if (cached) return cached;
      return fresh; // pass the error, but never store it
    }
    if (cached && fresh.status === 304) return cached;

    const res = new Response(fresh.body, fresh);
    if (fresh.status === 200) res.headers.set('Cache-Control', 'public, max-age=60');
    else if (fresh.status === 404) res.headers.set('Cache-Control', 'public, max-age=5');
    else res.headers.set('Cache-Control', 'no-store');
    if (res.status === 200 || res.status === 404) await cache.put(req, res.clone());
    return res;
  }
};

