const SOFT = 45_000, HARD = 90;

export async function readEntry(key: string) {
  const raw = await redis.get(key);
  return raw ? JSON.parse(raw) : null;
}

export async function refreshAhead(key: string, build: () => Promise<any>) {
  const got = await redis.set(`lock:${key}`, '1', 'NX', 'PX', 10_000);
  if (!got) return; // another rebuild in flight
  try {
    const data = await build();
    const entry = { data, softExpire: Date.now() + SOFT };
    await redis.set(key, JSON.stringify(entry), 'EX', HARD);
  } finally {
    await redis.del(`lock:${key}`);
  }
}

export async function refreshAheadBlocking(key: string, build: () => Promise<any>) {
  await refreshAhead(key, build);
  const e = await readEntry(key);
  return e ? e.data : await build();
}

