import { gzipSync, gunzipSync } from 'zlib';
const GZIP_MAGIC = 0x1f8b;

export function encodeTile(tile: any): Buffer {
  return gzipSync(Buffer.from(JSON.stringify(tile)));
}
export function decodeTile(raw: Buffer): any {
  const isGzip = raw.length > 2 && raw.readUInt16BE(0) === GZIP_MAGIC;
  const json = isGzip ? gunzipSync(raw) : raw; // legacy uncompressed fallback
  return JSON.parse(json.toString());
}

