import { rateLimit } from './ratelimit';

export async function lookupAccount(ref: string, ip: string) {
  if (!validRefFormat(ref)) return null;                 // cheap reject, no cache/DB
  if (!(await rateLimit(ip))) throw new Error('rate_limited');
  if (!(await maybeExistsRef(ref))) return null;         // definitely absent, no DB
  const cached = await redis.get(`acct:${ref}`);
  if (cached === 'NULL') return null;                    // negative cache
  if (cached) return JSON.parse(cached);
  const acct = await db.accountByRef(ref);
  if (acct) await redis.set(`acct:${ref}`, JSON.stringify(acct), 'EX', 600);
  else await redis.set(`acct:${ref}`, 'NULL', 'EX', 20); // short negative TTL
  return acct || null;
}

const REF_RE = /^[A-Z]{2}\d{10}$/;
export function validRefFormat(ref: string): boolean {
  return typeof ref === 'string' && REF_RE.test(ref); // reject malformed before any lookup
}

export async function rateLimit(ip: string, max = 50, windowSec = 1): Promise<boolean> {
  const key = `rl:${ip}:${Math.floor(Date.now()/1000)}`;
  const n = await redis.incr(key);
  if (n === 1) await redis.expire(key, windowSec);
  return n <= max;
}

it('malformed ref never hits cache or DB', async () => {
  let dbCalls = 0; db.accountByRef = async () => { dbCalls++; return null; };
  expect(await lookupAccount('bad', '1.1.1.1')).toBeNull();
  expect(dbCalls).toBe(0);
});
it('repeated absent ref hits DB at most once per TTL', async () => {
  let dbCalls = 0; db.accountByRef = async () => { dbCalls++; return null; };
  await seedFilter(['AB1234567890']);
  await lookupAccount('AB0000000000', '1.1.1.1');
  await lookupAccount('AB0000000000', '1.1.1.1');
  expect(dbCalls).toBeLessThanOrEqual(1);
});
